-- Create "chat_session_summaries" table
CREATE TABLE `chat_session_summaries` (
  `gram_project_id` UUID,
  `time_bucket` DateTime('UTC'),
  `chat_id` String,
  `session_user_email` SimpleAggregateFunction(max, String),
  `session_hook_source` SimpleAggregateFunction(max, String),
  `session_model` AggregateFunction(argMaxIf, String, Int64, UInt8),
  `start_time_unix_nano` SimpleAggregateFunction(min, Int64),
  `end_time_unix_nano` SimpleAggregateFunction(max, Int64),
  `message_count` AggregateFunction(uniqExactIf, String, UInt8),
  `tool_call_count` AggregateFunction(uniqExactIf, String, UInt8),
  `failed_tool_call_count` SimpleAggregateFunction(sum, UInt64),
  `total_input_tokens` SimpleAggregateFunction(sum, Int64),
  `total_output_tokens` SimpleAggregateFunction(sum, Int64),
  `total_tokens` SimpleAggregateFunction(sum, Int64),
  `cache_read_input_tokens` SimpleAggregateFunction(sum, Int64),
  `cache_creation_input_tokens` SimpleAggregateFunction(sum, Int64),
  `total_cost` SimpleAggregateFunction(sum, Float64),
  `department_names` SimpleAggregateFunction(groupUniqArrayArray, Array(String)),
  `job_titles` SimpleAggregateFunction(groupUniqArrayArray, Array(String)),
  `employee_types` SimpleAggregateFunction(groupUniqArrayArray, Array(String)),
  `division_names` SimpleAggregateFunction(groupUniqArrayArray, Array(String)),
  `cost_center_names` SimpleAggregateFunction(groupUniqArrayArray, Array(String)),
  `emails` SimpleAggregateFunction(groupUniqArrayArray, Array(String)),
  `hostnames` SimpleAggregateFunction(groupUniqArrayArray, Array(String)),
  `models` SimpleAggregateFunction(groupUniqArrayArray, Array(String)),
  `hook_sources` SimpleAggregateFunction(groupUniqArrayArray, Array(String)),
  `account_types` SimpleAggregateFunction(groupUniqArrayArray, Array(String)),
  `providers` SimpleAggregateFunction(groupUniqArrayArray, Array(String)),
  `billing_modes` SimpleAggregateFunction(groupUniqArrayArray, Array(String)),
  `roles` SimpleAggregateFunction(groupUniqArrayArray, Array(String)),
  `groups` SimpleAggregateFunction(groupUniqArrayArray, Array(String)),
  `attribution_tuples` SimpleAggregateFunction(groupUniqArrayArray, Array(Tuple(query_source String, skill_name String, agent_name String, mcp_server_name String, mcp_tool_name String)))
) ENGINE = AggregatingMergeTree
PRIMARY KEY (`gram_project_id`, `time_bucket`, `chat_id`) ORDER BY (`gram_project_id`, `time_bucket`, `chat_id`) TTL time_bucket + toIntervalDay(90) SETTINGS index_granularity = 8192 COMMENT 'Per-chat hourly session summaries powering the org-scoped sessions list (telemetry.listSessions) without scanning raw telemetry_logs';
-- Create "chat_session_summaries_mv" view
CREATE MATERIALIZED VIEW `chat_session_summaries_mv` TO `chat_session_summaries` AS WITH toUnixTimestamp64Nano(toDateTime64('2026-07-21 22:00:00', 9, 'UTC')) AS chat_session_cutoff_unix_nano, gram_urn = 'claude-code:otel:logs' AS is_claude_otel_row, is_claude_otel_row AND (chat_id != '') AND (toString(attributes.prompt.id) != '') AND ((toString(attributes.event.name) = 'api_request') OR (body = 'claude_code.api_request')) AS is_claude_api_request, is_claude_otel_row AND ((toString(attributes.event.name) = 'tool_result') OR (body = 'claude_code.tool_result')) AS is_claude_tool_result, startsWith(gram_urn, 'codex:usage') OR startsWith(gram_urn, 'cursor:usage') OR startsWith(gram_urn, 'claude_chat:usage') OR startsWith(gram_urn, 'claude_chat:cost') AS is_agent_usage_row, (hook_source IN ('codex', 'cursor')) AND (toString(attributes.gram.tool.name) != '') AND (toString(attributes.gram.tool.name) NOT IN ('claude-code', 'codex', 'cursor')) AND (toString(attributes.gram.hook.event) IN ('PostToolUse', 'PostToolUseFailure')) AS is_agent_tool_call, is_claude_tool_result OR is_agent_tool_call AS is_counted_tool_call, is_claude_api_request OR is_agent_usage_row AS is_usage_row, (is_claude_tool_result AND (toString(attributes.success) = 'false')) OR (is_agent_tool_call AND ((toString(attributes.gram.hook.event) = 'PostToolUseFailure') OR (toInt32OrZero(toString(attributes.http.response.status_code)) >= 400))) AS is_failed_tool_call, multiIf(toString(attributes.tool_use_id) != '', toString(attributes.tool_use_id), toString(attributes.gen_ai.tool.call.id) != '', toString(attributes.gen_ai.tool.call.id), toString(id)) AS tool_call_dedup_id, if(is_claude_api_request, toString(attributes.prompt.id), toString(attributes.gen_ai.response.id)) AS session_message_id, multiIf(is_claude_api_request AND (toString(attributes.model) != ''), toString(attributes.model), is_claude_api_request AND (toString(attributes.gen_ai.request.model) != ''), toString(attributes.gen_ai.request.model), toString(attributes.gen_ai.response.model)) AS effective_model SELECT gram_project_id, toStartOfHour(fromUnixTimestamp64Nano(time_unix_nano, 'UTC')) AS time_bucket, chat_id, max(user_email) AS session_user_email, max(hook_source) AS session_hook_source, argMaxIfState(effective_model, time_unix_nano, effective_model != '') AS session_model, min(time_unix_nano) AS start_time_unix_nano, max(time_unix_nano) AS end_time_unix_nano, uniqExactIfState(session_message_id, session_message_id != '') AS message_count, uniqExactIfState(tool_call_dedup_id, is_counted_tool_call) AS tool_call_count, countIf(is_failed_tool_call) AS failed_tool_call_count, sumIf(if(is_claude_api_request, toInt64OrZero(toString(attributes.input_tokens)), toInt64OrZero(toString(attributes.gen_ai.usage.input_tokens))), is_usage_row) AS total_input_tokens, sumIf(if(is_claude_api_request, toInt64OrZero(toString(attributes.output_tokens)), toInt64OrZero(toString(attributes.gen_ai.usage.output_tokens))), is_usage_row) AS total_output_tokens, sumIf(if(is_claude_api_request, (toInt64OrZero(toString(attributes.input_tokens)) + toInt64OrZero(toString(attributes.output_tokens))) + toInt64OrZero(toString(attributes.cache_creation_tokens)), (toInt64OrZero(toString(attributes.gen_ai.usage.input_tokens)) + toInt64OrZero(toString(attributes.gen_ai.usage.output_tokens))) + toInt64OrZero(toString(attributes.gen_ai.usage.cache_creation.input_tokens))), is_usage_row) AS total_tokens, sumIf(if(is_claude_api_request, toInt64OrZero(toString(attributes.cache_read_tokens)), toInt64OrZero(toString(attributes.gen_ai.usage.cache_read.input_tokens))), is_usage_row) AS cache_read_input_tokens, sumIf(if(is_claude_api_request, toInt64OrZero(toString(attributes.cache_creation_tokens)), toInt64OrZero(toString(attributes.gen_ai.usage.cache_creation.input_tokens))), is_usage_row) AS cache_creation_input_tokens, sumIf(if(is_claude_api_request, multiIf(toString(attributes.cost_usd) != '', toFloat64OrZero(toString(attributes.cost_usd)), toString(attributes.cost_usd_micros) != '', toFloat64OrZero(toString(attributes.cost_usd_micros)) / 1000000, 0), toFloat64OrZero(toString(attributes.gen_ai.usage.cost))), is_usage_row) AS total_cost, groupUniqArray(toString(attributes.user.attributes.department_name)) AS department_names, groupUniqArray(toString(attributes.user.attributes.job_title)) AS job_titles, groupUniqArray(toString(attributes.user.attributes.employee_type)) AS employee_types, groupUniqArray(toString(attributes.user.attributes.division_name)) AS division_names, groupUniqArray(toString(attributes.user.attributes.cost_center_name)) AS cost_center_names, groupUniqArray(if(user_email != '', user_email, toString(attributes.gram.hook.hostname))) AS emails, groupUniqArray(toString(attributes.gram.hook.hostname)) AS hostnames, groupUniqArray(effective_model) AS models, groupUniqArray(hook_source) AS hook_sources, groupUniqArray(account_type) AS account_types, groupUniqArray(provider) AS providers, groupUniqArray(billing_mode) AS billing_modes, groupUniqArrayArray(arraySort(JSONExtract(ifNull(toJSONString(attributes.user.roles), '[]'), 'Array(String)'))) AS roles, groupUniqArrayArray(arraySort(JSONExtract(ifNull(toJSONString(attributes.user.groups), '[]'), 'Array(String)'))) AS groups, groupUniqArrayIf((toString(attributes.query_source), toString(attributes.skill.name), toString(attributes.agent.name), toString(attributes.mcp_server.name), toString(attributes.mcp_tool.name)), is_claude_api_request) AS attribution_tuples FROM telemetry_logs WHERE (time_unix_nano >= chat_session_cutoff_unix_nano) AND (chat_id != '') AND (is_claude_api_request OR is_claude_tool_result OR is_agent_usage_row OR is_agent_tool_call) GROUP BY gram_project_id, time_bucket, chat_id;
